import React, { useState } from 'react';
import { Product } from '../types';

interface Review {
  id: number;
  user: string;
  time: string;
  content: string;
  product: string;
  reply?: string;
}

const mockReviews: Review[] = [
  {
    id: 1,
    user: 'Sol****',
    time: '2시간전',
    content: '진행 과정도 결과도 만족합니다. 그리고 문의에 친절하게 설명해주십니다.',
    product: '유튜브 구독자,조회수,쇼츠,시청시간,수익창출,스트리밍',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 2,
    user: '살*****',
    time: '20시간전',
    content: '친절하게 잘 설명해주시고 바로바로 피드백 주셔서 너무 좋습니다!',
    product: '애드모어',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 3,
    user: 'K31***',
    time: '하루전',
    content: '수고하셨습니다. 감사합니다.',
    product: '인스타그램 팔로워,릴스,좋아요,조회수,인기게시물 관리',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 4,
    user: '방**',
    time: '하루전',
    content: '빠른 대응과 기대이상의 결과물로 매우 만족 합니다.',
    product: '유튜브 구독자,조회수,쇼츠,시청시간,수익창출,스트리밍',
    reply: '소중한 후기를 남겨주셔서 진심으로 감사드립니다. 애드모어는 최상의 결과를 제공하기 위해 끊임없이 노력하고 있습니다. 앞으로도 한 걸음 더 나아가 최고의 서비스를 제공하기 위해 최선을 다하겠습니다. 함께 만들어가는 이 여정에 함께해 주셔서 감사합니다.'
  },
  {
    id: 5,
    user: '에*****',
    time: '2025-06-28',
    content: '항상 작업물의 퀄리티, 속도와 처리가 매우 만족을 줍니다. 대응도 신속하고 빠르며 친절한 설명에 많은 도움이 됩니다. 다음에 또 구매하겠습니다. 감사합니다.',
    product: '유튜브 구독자,조회수,쇼츠,시청시간,수익창출,스트리밍',
  },
];

const sortOptions = [
  { value: 'latest', label: '최신순' },
  { value: 'high', label: '평점 높은 순' },
  { value: 'low', label: '평점 낮은 순' },
];

const Reviews: React.FC = () => {
  const [activeTab, setActiveTab] = useState<string>('favorites');
  const [recentProducts, setRecentProducts] = useState<Product[]>([]);
  const [sort, setSort] = useState('latest');

  // Mock data for favorites
  const favorites: Product[] = [
    {
      id: 1,
      name: '페이스북 팔로워 1000명',
      price: '50,000원',
      category: '페이스북',
      image: 'https://via.placeholder.com/200x150?text=Facebook',
      addedDate: '2024-01-15'
    },
    {
      id: 2,
      name: '인스타그램 팔로워 500명',
      price: '30,000원',
      category: '인스타그램',
      image: 'https://via.placeholder.com/200x150?text=Instagram',
      addedDate: '2024-01-10'
    },
    {
      id: 3,
      name: '유튜브 구독자 1000명',
      price: '100,000원',
      category: '유튜브',
      image: 'https://via.placeholder.com/200x150?text=YouTube',
      addedDate: '2024-01-08'
    },
    {
      id: 4,
      name: '블로그 방문자 5000명',
      price: '80,000원',
      category: '블로그',
      image: 'https://via.placeholder.com/200x150?text=Blog',
      addedDate: '2024-01-05'
    }
  ];

  const handleRemoveFavorite = (id: number): void => {
    // Here you would typically remove the item from favorites
    console.log('Removing favorite:', id);
    alert('즐겨찾기에서 제거되었습니다.');
  };

  const handleRemoveAllFavorites = (): void => {
    if (window.confirm('모든 즐겨찾기를 삭제하시겠습니까?')) {
      // Here you would typically clear all favorites
      console.log('Clearing all favorites');
      alert('모든 즐겨찾기가 삭제되었습니다.');
    }
  };

  const handleRemoveAllRecent = (): void => {
    if (window.confirm('모든 최근 본 상품을 삭제하시겠습니까?')) {
      // Here you would typically clear all recent products
      console.log('Clearing all recent products');
      alert('모든 최근 본 상품이 삭제되었습니다.');
    }
  };

  // 실제 정렬 로직은 생략 (mock 데이터)
  const reviews = mockReviews;

  return (
    <div className="min-h-screen bg-gray-50 py-8 mb-20">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Page Header */}
        <div className="mb-8">
          <div className="flex justify-center items-center mb-4">
            <h1 className="text-3xl font-bold text-gray-900 text-center">리뷰목록</h1>
            <span className="text-gray-600 text-center ml-2">총 100개의 리뷰</span>
          </div>
            <p className="text-gray-600 text-center">실제로 구매하신 고객님들의 후기를 확인해보세요.</p>
        </div>


        {/* Review List */}
        <div className="space-y-8">
          {reviews.map(review => (
            <div key={review.id} className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center mb-2">
                <span className="font-semibold text-blue-600 mr-2">{review.user}</span>
                <span className="text-xs text-gray-400">{review.time}</span>
              </div>
              <div className="mb-2 text-gray-900">{review.content}</div>
              <div className="text-xs text-gray-500 mb-2">{review.product}</div>
              {review.reply && (
                <div className="bg-gray-50 border-l-4 border-blue-400 p-3 text-sm text-gray-700 mt-2">
                  <span className="font-bold text-blue-600">애드모어</span> <span className="ml-2">{review.reply}</span>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Pagination (간단하게) */}
        <div className="flex justify-center mt-10">
